(resolver.pipelineFunctionLogicalIds.length > 0
          ? {
              pipelineFunctions: resolver.pipelineFunctionLogicalIds.map(
                (logicalId) => {
                  const fn = functionById.get(logicalId) ?? null;
                  return {
                    logicalId,
                    name: fn?.name ?? null,
                    dataSourceLogicalId: fn?.dataSourceLogicalId ?? null,
                  };
                },
              ),
            }
          : {})
